      const mockResponse = { data: { token: 'jwt-token-abc', expiresIn: 86400 } }
      vi.mocked(api.post).mockResolvedValue(mockResponse)

      await login('testuser', 'password123')

      expect(localStorage.getItem('token')).toBe('jwt-token-abc')
    })

    it('should return the response data', async () => {
      const mockData = { token: 'jwt-token', expiresIn: 86400 }
      vi.mocked(api.post).mockResolvedValue({ data: mockData })

      const result = await login('testuser', 'password123')

      expect(result).toEqual(mockData)
    })
  })

  describe('register', () => {
    it('should POST to /auth/register with username, password, and displayName', async () => {
      const mockResponse = { data: { id: 1, username: 'newuser', displayName: 'New User' } }
