    it('should return the response data', async () => {
      const mockData = { id: 1, username: 'newuser', displayName: 'New User' }
      vi.mocked(api.post).mockResolvedValue({ data: mockData })

      const result = await register('newuser', 'password123', 'New User')

      expect(result).toEqual(mockData)
    })
  })

  describe('getMe', () => {
    it('should GET /auth/me', async () => {
      const mockResponse = { data: { id: 1, username: 'testuser', displayName: 'Test' } }
      vi.mocked(api.get).mockResolvedValue(mockResponse)

      await getMe()

      expect(api.get).toHaveBeenCalledWith('/auth/me')
