      await fetchTasks({ page: 0, size: 10, keyword: 'test', priority: 'HIGH', status: 'TODO' })

      expect(api.get).toHaveBeenCalledWith('/tasks', {
        params: { page: 0, size: 10, keyword: 'test', priority: 'HIGH', status: 'TODO' },
      })
    })

    it('should return the response data', async () => {
      const mockData = {
        content: [{ id: 1, title: 'Task 1' }],
        page: 0,
        size: 20,
        totalElements: 1,
        totalPages: 1,
      }
      vi.mocked(api.get).mockResolvedValue({ data: mockData })

      const result = await fetchTasks({ page: 0, size: 20 })

      expect(result).toEqual(mockData)
    })
  })

  describe('getTask', () => {
    it('should GET /tasks/{id}', async () => {
      const mockResponse = { data: { id: 42, title: 'Task 42' } }
      vi.mocked(api.get).mockResolvedValue(mockResponse)

      await getTask(42)

      expect(api.get).toHaveBeenCalledWith('/tasks/42')
    })

    it('should return the response data', async () => {
      const mockData = { id: 42, title: 'Task 42' }
      vi.mocked(api.get).mockResolvedValue({ data: mockData })

      const result = await getTask(42)

      expect(result).toEqual(mockData)
    })
  })

  describe('createTask', () => {
    it('should POST /tasks with task data', async () => {
      const taskData = { title: 'New Task', description: 'Desc', priority: 'HIGH' as const }
      const mockResponse = { data: { id: 1, ...taskData, status: 'TODO' } }
      vi.mocked(api.post).mockResolvedValue(mockResponse)

      await createTask(taskData)

      expect(api.post).toHaveBeenCalledWith('/tasks', taskData)
    })

    it('should return the response data', async () => {
      const mockData = { id: 1, title: 'New Task', status: 'TODO' }
      vi.mocked(api.post).mockResolvedValue({ data: mockData })

      const result = await createTask({ title: 'New Task' })

      expect(result).toEqual(mockData)
    })
  })

  describe('updateTask', () => {
    it('should PUT /tasks/{id} with updated data', async () => {
      const updateData = { title: 'Updated', description: 'New desc', priority: 'LOW' as const }
      const mockResponse = { data: { id: 5, ...updateData } }
      vi.mocked(api.put).mockResolvedValue(mockResponse)

      await updateTask(5, updateData)

      expect(api.put).toHaveBeenCalledWith('/tasks/5', updateData)
    })

    it('should return the response data', async () => {
      const mockData = { id: 5, title: 'Updated' }
      vi.mocked(api.put).mockResolvedValue({ data: mockData })

      const result = await updateTask(5, { title: 'Updated' })

      expect(result).toEqual(mockData)
    })
  })

  describe('deleteTask', () => {
    it('should DELETE /tasks/{id}', async () => {
      vi.mocked(api.delete).mockResolvedValue({ status: 204 })

      await deleteTask(10)

      expect(api.delete).toHaveBeenCalledWith('/tasks/10')
    })
  })

  describe('changeStatus', () => {
    it('should PATCH /tasks/{id}/status with new status', async () => {
      const mockResponse = { data: { id: 3, status: 'IN_PROGRESS' } }
      vi.mocked(api.patch).mockResolvedValue(mockResponse)

      await changeStatus(3, 'IN_PROGRESS')

      expect(api.patch).toHaveBeenCalledWith('/tasks/3/status', { status: 'IN_PROGRESS' })
    })

    it('should return the response data', async () => {
      const mockData = { id: 3, status: 'DONE' }
      vi.mocked(api.patch).mockResolvedValue({ data: mockData })

      const result = await changeStatus(3, 'DONE')

      expect(result).toEqual(mockData)
    })
  })

  describe('getTransitions', () => {
    it('should GET /tasks/{id}/transitions', async () => {
      const mockResponse = {
        data: { currentStatus: 'TODO', availableTransitions: ['IN_PROGRESS'] },
      }
      vi.mocked(api.get).mockResolvedValue(mockResponse)

      await getTransitions(7)

      expect(api.get).toHaveBeenCalledWith('/tasks/7/transitions')
    })

    it('should return the response data', async () => {
      const mockData = { currentStatus: 'IN_PROGRESS', availableTransitions: ['TODO', 'DONE'] }
      vi.mocked(api.get).mockResolvedValue({ data: mockData })

      const result = await getTransitions(7)

      expect(result).toEqual(mockData)
    })
  })
})

